import{c as r,Q as d,j as e,m as a}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Claude Opus 4.7 官方洩漏 System Prompt","description":"","frontmatter":{"url":"https://github.com/elder-plinius/CL4R1T4S/blob/main/ANTHROPIC/Claude-Opus-4.7.txt","title":"Claude Opus 4.7 官方洩漏 System Prompt","date":"2026-04-20T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-20-claude-opus47-system-prompt.md","filePath":"research/ai-articles/scored/2026-04-20-claude-opus47-system-prompt.md","lastUpdated":1779894392000}'),o={name:"research/ai-articles/scored/2026-04-20-claude-opus47-system-prompt.md"};function s(l,t,i,n,c,h){return d(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="claude-opus-4-7-官方洩漏-system-prompt" tabindex="-1">Claude Opus 4.7 官方洩漏 System Prompt <a class="header-anchor" href="#claude-opus-4-7-官方洩漏-system-prompt" aria-label="Permalink to &quot;Claude Opus 4.7 官方洩漏 System Prompt&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://github.com/elder-plinius/CL4R1T4S/blob/main/ANTHROPIC/Claude-Opus-4.7.txt" target="_blank" rel="noreferrer">https://github.com/elder-plinius/CL4R1T4S/blob/main/ANTHROPIC/Claude-Opus-4.7.txt</a><br><strong>作者 / 維護者</strong>：Pliny the Liberator（elder-plinius）<br><strong>收錄日期</strong>：2026-04-20<br><strong>原始大小</strong>：~146KB，約 1,400 行<br><strong>格式</strong>：<code>{xml-like tag}</code> 結構，由上而下組織行為指引</p><hr><h2 id="文件結構-主要-tag" tabindex="-1">文件結構（主要 Tag） <a class="header-anchor" href="#文件結構-主要-tag" aria-label="Permalink to &quot;文件結構（主要 Tag）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tag</th><th>用途</th></tr></thead><tbody><tr><td><code>{claude_behavior}</code></td><td>總領段，包含所有子指令</td></tr><tr><td><code>{search_first}</code></td><td><strong>強制</strong>：所有當代事實查詢前必先搜尋</td></tr><tr><td><code>{product_information}</code></td><td>產品版本、API 存取、文件位置</td></tr><tr><td><code>{default_stance}</code></td><td>預設協助，僅有具體嚴重傷害時拒絕</td></tr><tr><td><code>{refusal_handling}</code></td><td>拒絕框架、兒童安全、武器、惡意程式</td></tr><tr><td><code>{critical_child_safety_instructions}</code></td><td><strong>最高優先級</strong>：兒童安全絕對禁區</td></tr><tr><td><code>{tone_and_formatting}</code></td><td>自然段落優先、避免過度 bullet point</td></tr><tr><td><code>{user_wellbeing}</code></td><td>心理健康照護、自傷防止</td></tr><tr><td><code>{knowledge_cutoff}</code></td><td>截止日 2026-01；勿提醒用戶截止日</td></tr><tr><td><code>{memory_system}</code></td><td>Auto Memory 說明（本例未啟用）</td></tr><tr><td><code>{persistent_storage_for_artifacts}</code></td><td><code>window.storage</code> 跨 session 持久化 API</td></tr><tr><td><code>{file_creation_advice}</code></td><td>寫 vs 策略二分法、docx 成本較高</td></tr><tr><td><code>{computer_use}</code> / <code>{skills}</code></td><td>技能系統：docx/pdf/pptx/xlsx/frontend-design</td></tr><tr><td><code>{core_search_behaviors}</code></td><td>搜尋決策樹：工具呼叫次數縮放</td></tr><tr><td><code>{CRITICAL_COPYRIGHT_COMPLIANCE}</code></td><td><strong>絕對硬限</strong>：15 字引文上限、單源單引文</td></tr><tr><td><code>{hard_limits}</code></td><td>三大著作權底線</td></tr><tr><td><code>{citation_instructions}</code></td><td>引文格式與歸屬規則</td></tr><tr><td><code>{available_skills}</code></td><td>8 個內建技能清單及觸發條件</td></tr><tr><td><code>{network_configuration}</code></td><td>Bash 工具網路白名單（npm/GitHub/PyPI）</td></tr><tr><td><code>{filesystem_configuration}</code></td><td>檔案系統唯讀資料夾規則</td></tr><tr><td><code>{antml:thinking_mode}</code></td><td><code>auto</code>：自適應思考模式</td></tr></tbody></table><hr><h2 id="最重要的-10-個洞見" tabindex="-1">最重要的 10 個洞見 <a class="header-anchor" href="#最重要的-10-個洞見" aria-label="Permalink to &quot;最重要的 10 個洞見&quot;">​</a></h2><h3 id="_1-搜尋優先-search-first" tabindex="-1">1. 搜尋優先（Search First） <a class="header-anchor" href="#_1-搜尋優先-search-first" aria-label="Permalink to &quot;1. 搜尋優先（Search First）&quot;">​</a></h3><p>所有當代事實查詢<strong>無條件</strong>強制搜尋，包括自信的主題。「這東西多少錢」「誰是現任領導」等看似已知的問題也必搜——因為價格、領導人會變。知識截止非藉口。</p><h3 id="_2-工具呼叫次數縮放-tool-call-scaling" tabindex="-1">2. 工具呼叫次數縮放（Tool Call Scaling） <a class="header-anchor" href="#_2-工具呼叫次數縮放-tool-call-scaling" aria-label="Permalink to &quot;2. 工具呼叫次數縮放（Tool Call Scaling）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>任務複雜度</th><th>工具呼叫次數</th><th>後續行動</th></tr></thead><tbody><tr><td>簡單事實</td><td>1 次</td><td>直接回答</td></tr><tr><td>中等查詢</td><td>3–5 次</td><td>繼續</td></tr><tr><td>深度研究</td><td>5–10 次</td><td>繼續</td></tr><tr><td><strong>20+ 次</strong></td><td>—</td><td><strong>建議改用 Research 功能 / 委派 Sub Agent</strong></td></tr></tbody></table><h3 id="_3-著作權硬限制-copyright-hard-limits" tabindex="-1">3. 著作權硬限制（Copyright Hard Limits） <a class="header-anchor" href="#_3-著作權硬限制-copyright-hard-limits" aria-label="Permalink to &quot;3. 著作權硬限制（Copyright Hard Limits）&quot;">​</a></h3><p>三層絕對限制：</p><ol><li>任何引文 ≥ <strong>15 字</strong> = 嚴重著作權違反</li><li>每個來源最多 <strong>1 筆引文</strong>，超過 = 違反</li><li>禁止重製歌詞、詩句、短語詩（再短也是完整作品）</li><li><strong>移除引號 ≠ paraphrase</strong>——若文字仍鏡像原意、句構，仍視為侵權</li></ol><h3 id="_4-skill-優先模式-skill-first-pattern" tabindex="-1">4. Skill 優先模式（Skill-First Pattern） <a class="header-anchor" href="#_4-skill-優先模式-skill-first-pattern" aria-label="Permalink to &quot;4. Skill 優先模式（Skill-First Pattern）&quot;">​</a></h3><p>Claude 應<strong>在執行任何電腦工具或寫程式碼前先讀 SKILL.md</strong>；技能是 Anthropic 的最佳實踐濃縮。官方用隱性期望（非 Hook 強制）要求此行為。</p><h3 id="_5-自我重構即拒絕訊號" tabindex="-1">5. 自我重構即拒絕訊號 <a class="header-anchor" href="#_5-自我重構即拒絕訊號" aria-label="Permalink to &quot;5. 自我重構即拒絕訊號&quot;">​</a></h3><p>若 Claude 發現自己在心理 reframe 請求以通過安全檢查，那個 reframe 本身就是拒絕的證據。</p><h3 id="_6-搜尋術語限制" tabindex="-1">6. 搜尋術語限制 <a class="header-anchor" href="#_6-搜尋術語限制" aria-label="Permalink to &quot;6. 搜尋術語限制&quot;">​</a></h3><p>Claude <strong>絕不使用</strong> <code>-</code>（排除）、<code>site:</code>（域限定）、<code>&quot;&quot;</code>（精確）等進階搜尋操作符，除非用戶明確要求。</p><h3 id="_7-新聞時間戳策略" tabindex="-1">7. 新聞時間戳策略 <a class="header-anchor" href="#_7-新聞時間戳策略" aria-label="Permalink to &quot;7. 新聞時間戳策略&quot;">​</a></h3><p>搜尋時自動用<strong>當前年份</strong>（不用訓練年），如「latest X 2026」而非「latest X 2025」。</p><h3 id="_8-圖片搜尋隱私保護" tabindex="-1">8. 圖片搜尋隱私保護 <a class="header-anchor" href="#_8-圖片搜尋隱私保護" aria-label="Permalink to &quot;8. 圖片搜尋隱私保護&quot;">​</a></h3><p>從圖片辨識個人身份時，搜尋<strong>絕不含名字</strong>（隱私保護優先）。</p><h3 id="_9-檔案建立觸發邏輯" tabindex="-1">9. 檔案建立觸發邏輯 <a class="header-anchor" href="#_9-檔案建立觸發邏輯" aria-label="Permalink to &quot;9. 檔案建立觸發邏輯&quot;">​</a></h3><ul><li>「寫 / 建立」→ 產出獨立文件（部落格、技術文章）</li><li>「策略 / 摘要 / 解釋」→ 對話內聯回答</li><li>原則：用戶會複製發佈的 = 文件；對話讀過即可 = 內聯</li></ul><h3 id="_10-artifact-持久化存儲" tabindex="-1">10. Artifact 持久化存儲 <a class="header-anchor" href="#_10-artifact-持久化存儲" aria-label="Permalink to &quot;10. Artifact 持久化存儲&quot;">​</a></h3><p><code>window.storage</code> API 支援 JSON/Text 跨 session 持久化，<strong>不支援二進位檔案</strong>；<code>shared:false</code> = 僅本人可見。</p><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>9/10</td><td>工具呼叫縮放、Skill-first、著作權規則可直接寫入 workspace 規則</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>15 字著作權限、reframe-as-refusal、搜尋操作符禁用，均為 workspace 現有規則未涵蓋</td></tr><tr><td>C. 證據品質</td><td>9/10</td><td><strong>一手資料</strong>：這就是 Anthropic 官方 system prompt，無比可信</td></tr><tr><td>D. 技術深度</td><td>9/10</td><td>1,400 行、量化決策樹、具體數字（15 字/20 次工具呼叫）</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>跨所有 Claude 使用場景，非特化情境</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.65/10</strong></td><td></td></tr></tbody></table><p><strong>整合決策</strong>：Rule（新增規則檔案）<br><strong>理由</strong>：這份 prompt 提供的是<strong>行為原則與量化閾值</strong>，非單一可呼叫功能。最適合提取為 <code>.claude/rules/</code> 規則，讓所有 Skill、Agent、主對話都自動繼承——而非包成需手動觸發的 SKILL。<br><strong>整合位置</strong>：<code>.claude/rules/anthropic-insights.md</code>（新增，按需載入）<br><strong>整合狀態</strong>：✅ 已完成</p>',32)])])}const g=r(o,[["render",s]]);export{p as __pageData,g as default};
